// TM for language L = {0^n 1^n | n ≥ 1}
// States: q0 (start/scan 0), q1 (scan to find 1), q2 (return), q_accept, q_reject
// Tape symbols: {0, 1, X, Y, ☐}

BEGIN
// Phase 1: Replace leftmost 0 with X
TRANSITION(q0, 0): 
    WRITE('X')
    MOVE(RIGHT)
    GOTO q1

// Phase 2: Skip 0s to find first 1
TRANSITION(q1, 0):
    MOVE(RIGHT)
    GOTO q1

TRANSITION(q1, 1):
    WRITE('Y')
    MOVE(LEFT)
    GOTO q2

// Phase 3: Move back to find next X
TRANSITION(q2, 0):
    MOVE(LEFT)
    GOTO q2

TRANSITION(q2, X):
    MOVE(RIGHT)
    GOTO q0

// Check for completion: All 0s replaced (X) and all 1s replaced (Y)
TRANSITION(q0, Y):
    MOVE(RIGHT)
    GOTO q0

TRANSITION(q0, ☐):
    GOTO q_accept

// Reject states for invalid patterns
TRANSITION(q1, ☐): GOTO q_reject
END

// Universal Turing Machine (UTM)
// Input: <M>#w where M is encoding of TM, w is input string
// Output: Same as M would produce on input w

BEGIN
// Initialize: Copy M's description to work area
// Encode input w on simulation tape

// Main simulation loop
REPEAT
    // Find current state of M from encoded configuration
    current_state = READ_STATE(encoding_tape)
    current_symbol = READ_TAPE(simulated_tape)

    // Look up transition δ(current_state, current_symbol)
    transition = LOOKUP_TRANSITION(M_encoding, current_state, current_symbol)

    IF transition EXISTS THEN
        // Execute the transition
        WRITE(transition.new_symbol)
        MOVE(transition.direction)
        UPDATE_STATE(transition.new_state)
    ELSE
        // No transition defined - simulation ends
        BREAK
    END IF
UNTIL state = q_accept OR state = q_reject

// Output: If q_accept reached, UTM accepts; else rejects
END

// Simulate k-tape TM using single-tape TM
// Input tape layout: #marker1#marker2#...#marker_k#
// Each section contains symbols from corresponding tape

BEGIN
// Setup: Encode k-tape content on single tape
// Format: ☐t1[1]t1[2]...#1#t2[1]t2[2]...#2#...#k#tk[1]tk[2]...
// Markers (#1, #2, etc.) show head positions

REPEAT
    // Phase 1: Scan entire tape to determine (state, symbols at all heads)
    // Store current configuration
    current_state = state_at_start
    symbols_read = []
    FOR i = 1 TO k:
        symbols_read[i] = symbol_after_marker_i
    END FOR

    // Phase 2: Look up transition δ(current_state, symbols_read)
    // Suppose δ(q, a1...ak) = (p, b1...bk, D1...Dk)

    // Phase 3: Update tape - write new symbols
    FOR i = 1 TO k:
        replace symbol_after_marker_i with b_i
    END FOR

    // Phase 4: Move markers based on directions
    FOR i = 1 TO k:
        IF D_i = 'R' THEN
            move marker_i one position right
        ELSE IF D_i = 'L' THEN
            move marker_i one position left
        // If 'S' (stay), marker stays
    END FOR

    current_state = p

UNTIL current_state = q_accept OR current_state = q_reject
// or loop forever if original TM would loop
END
